// This code processes the Intercom API response and returns all matching contacts
// Get the current item's data
const item = $input.item.json;
// Get the publisher_name from the previous node (database query result)
const publisherName = $('Madmin').item.json.publisher_name;
const productName = $('Madmin').item.json.contact_product_name;
const resultType = $('Madmin').item.json.result_type;

// Check if Intercom returned any contacts
let matchingContacts = [];
let hasIntercomData = false;
if (item && item.data && item.data.length > 0 && item.total_count > 0) {
  // Filter contacts based on criteria
  matchingContacts = item.data.filter(contact => {
    // Check 1: external_id must start with "p_"
    const hasValidExternalId = contact.external_id && contact.external_id.startsWith('p_');

    // Check 2: custom_attributes.publishers OR custom_attributes.developers must equal publisherName (case-insensitive)
    const customAttrs = contact.custom_attributes || {};
    const publisherNameLower = publisherName ? publisherName.toLowerCase() : '';
const publishersLower = customAttrs.Publishers ? customAttrs.Publishers.toLowerCase() : '';
const developersLower = customAttrs.Developers ? customAttrs.Developers.toLowerCase() : '';

    const publisherMatch = publishersLower === publisherNameLower || 
                          developersLower === publisherNameLower;

    return hasValidExternalId && publisherMatch;
  }).map(contact => ({
    id: contact.id,
    external_id: contact.external_id,
    email: contact.email,
    name: contact.name,
    created_at: contact.created_at,
    updated_at: contact.updated_at,
    custom_attributes: contact.custom_attributes,
    tags: contact.tags?.data?.length || 0
  }));

  hasIntercomData = matchingContacts.length > 0;
}
// Build the output object
const output = {
  // Database query results
  result_type: resultType,
  publisher_name: publisherName,
  product_name: productName,

  // Intercom search results
  intercom_found: hasIntercomData,
  intercom_total_count: item.total_count || 0,
  intercom_matching_count: matchingContacts.length,

  // If no Intercom data, show what we searched for
  searched_publisher: hasIntercomData ? null : publisherName,

  // All matching Intercom contacts (array)
  intercom_contacts: hasIntercomData ? matchingContacts : []
};
return output;

// Get publisher_name original
const publisherOriginal = $node["Loop ActiveCampaign"].json.publisher_name;

// Lowercase version (for matching only)
const publisherName = publisherOriginal?.toLowerCase().trim();

// Get organizations array from current item
const orgs = $json.organizations || [];

let match = null;

// Loop and find exact match
for (const org of orgs) {
  const orgName = org.name?.toLowerCase().trim();

  if (orgName === publisherName) {
    match = org;
    break;
  }
}

// Return result (IMPORTANT: no array wrapper)
if (match) {
  return {
    json: {
      message: "found",
      ...match
    }
  };
} else {
  return {
    json: {
      message: "not found",
      publisher_name: publisherOriginal
    }
  };
}

const inputPublisher = $input.item.json.publisher_name?.toLowerCase().trim();
const rows = $items("Input Modify");

let found = null;
for (const item of rows) {
  const publisher = item.json.publisher_name?.toLowerCase().trim();
  if (publisher === inputPublisher) {
    found = JSON.parse(JSON.stringify(item.json));
    break;
  }
}

if (found) {
  return {
    json: {
      product_name: String(found.product_name ?? ""),
      publisher_name: String(found.publisher_name ?? ""),
      url_web: String(found.url_web ?? ""),
      url_email: String(found.url_email ?? "")
    }
  };
}

return {
  json: {
    product_name: "",
    publisher_name: String($input.item.json.publisher_name ?? ""),
    url_web: "",
    url_email: "",
    message: "publisher not found in Input Modify"
  }
};

// flatten all accountContacts from all items
let result = [];
for (const item of $input.all()) {
  result.push(...(item.json.accountContacts || []));
}
return result.map(contact => ({ json: contact }));

// Get all input items from the previous node
const allItems = $input.all();

// Return everything as-is
return allItems;

// Get all incoming items
const items = $input.all();

// Filter only tracker === "not found"
const filtered = items
  .map(item => item.json)
  .filter(item => item.tracker === "not found")
  .map(item => ({
    json: {
      publisher_name: item.publisher_name,
      tracker: item.tracker
    }
  }));

return filtered;

// Get all incoming items
const items = $input.all();

// Filter only tracker === "not found"
const filtered = items
  .map(item => item.json)
  .filter(item => item.tracker === "not found")
  .map(item => ({
    json: {
      publisher_name: item.publisher_name,
      tracker: item.tracker
    }
  }));

return filtered;

// Get data from specific nodes
const v1 = $items("Filter Tracker v1").map(item => item.json);
const v2 = $items("Filter Tracker v2").map(item => item.json);

// Get publisher names from v2
const v2Names = new Set(v2.map(item => item.publisher_name));

// Find matching publisher_name in both
const result = v1
  .filter(item => v2Names.has(item.publisher_name))
  .map(item => ({
    publisher_name: item.publisher_name,
    tracker: "not found"
  }));

return result.map(item => ({ json: item }));

// Get data from the previous node (accountContacts data)
const accountContactsData = $input.all();

// Get data from the "Get Found Data" node (accounts data)
const accountsData = $('Get Found Data').all();

const results = [];

for (const accountItem of accountsData) {
  const account = accountItem.json;
  const accountId = account.id;

  // Find matching entry in accountContacts data
  const matchingEntry = accountContactsData.find(item => {
    const contacts = item.json.accountContacts;
    // Check if any contact in this entry has account === accountId
    return Array.isArray(contacts) && contacts.some(c => c.account === accountId);
  });

  if (!matchingEntry) {
    // No match found OR accountContacts is empty — return name + flag
    results.push({
      json: {
        name: account.name,
        id: accountId,
        isAccountContactsEmpty: true
      }
    });
    continue;
  }

  const contacts = matchingEntry.json.accountContacts;
  const isEmpty = !Array.isArray(contacts) || contacts.length === 0;

  if (isEmpty) {
    results.push({
      json: {
        id: accountId,
        name: account.name,
        isAccountContactsEmpty: true
      }
    });
  } else {
    // Return the full accountContacts array with the flag
    results.push({
      json: {
        ...matchingEntry.json,
        accountName: account.name,
        isAccountContactsEmpty: false
      }
    });
  }
}

return results;

// Get data from previous node (contact/account data)
const contactItems = $input.all();

// Get data from the node before that (publisher/developer data)
const publisherItems = $('Input').all();

// Build a lookup map from publisher/developer names (lowercase for case-insensitive matching)
const publisherMap = {};
for (const item of publisherItems) {
  const name = item.json['publisher / developer name'];
  if (name) {
    publisherMap[name.toLowerCase()] = name; // key: lowercase, value: original casing
  }
}

// Process each contact item and update account names if a match is found
const results = [];

for (const item of contactItems) {
  const data = JSON.parse(JSON.stringify(item.json)); // deep clone

  if (data.accounts && Array.isArray(data.accounts)) {
    data.accounts = data.accounts.map(account => {
      if (account.name) {
        const matchedName = publisherMap[account.name.toLowerCase()];
        if (matchedName) {
          return { ...account, name: matchedName };
        }
      }
      return account;
    });
  }

  results.push({ json: data });
}

return results;
